static inline void decodeV1SimpleLogoRow(uint16_t row, uint16_t* dest, size_t destCount = V1SIMPLE_LOGO_WIDTH) {
    if (!dest || row >= V1SIMPLE_LOGO_HEIGHT || destCount < V1SIMPLE_LOGO_WIDTH) {
        return;
    }

    uint16_t runIndex = pgm_read_word(&v1simple_logo_row_start_run[row]);
    uint16_t runSkip = pgm_read_word(&v1simple_logo_row_start_skip[row]);
    size_t written = 0;

    while (written < V1SIMPLE_LOGO_WIDTH && runIndex < V1SIMPLE_LOGO_RUN_COUNT) {
        const uint32_t packedRun = pgm_read_dword(&v1simple_logo_runs[runIndex]);
        const uint16_t color = static_cast<uint16_t>(packedRun & 0xFFFFU);
        const uint16_t count = static_cast<uint16_t>(packedRun >> 16);
        uint16_t available = static_cast<uint16_t>(count - runSkip);
        if (available > (V1SIMPLE_LOGO_WIDTH - written)) {
            available = static_cast<uint16_t>(V1SIMPLE_LOGO_WIDTH - written);
        }
        for (uint16_t i = 0; i < available; ++i) {
            dest[written++] = color;
        }
        ++runIndex;
        runSkip = 0;
    }
}

